import React from 'react';
import { getProductName, getImagePath, getShirtVersionTotal } from '../utils';
import { ShirtVersion } from '../types';

interface ShirtVersionCardProps {
  categoryPath: string;
  imageName: string;
  shirtVersions?: ShirtVersion;
  onShirtVersionChange?: (imagePath: string, version: keyof ShirtVersion, value: string) => void;
  readOnly?: boolean;
}

const ShirtVersionCard: React.FC<ShirtVersionCardProps> = ({
  categoryPath,
  imageName,
  shirtVersions = { tshirt: '', longsleeve: '', hoodie: '' },
  onShirtVersionChange,
  readOnly = false
}) => {
  const imagePath = getImagePath(categoryPath, imageName);
  const productName = getProductName(imageName);
  const totalQuantity = getShirtVersionTotal(shirtVersions);

  const handleVersionChange = (version: keyof ShirtVersion, value: string) => {
    onShirtVersionChange?.(imagePath, version, value);
  };

  return (
    <div style={{ width: 200, marginBottom: 'var(--space-2)' }}>
      <img
        src={process.env.PUBLIC_URL + `/MichiganState/${imagePath}`}
        alt={imageName}
        style={{ width: '100%', borderRadius: 'var(--radius)', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}
      />
      <div style={{ fontSize: 12, marginTop: 4, marginBottom: 4 }}>{productName}</div>

      {!readOnly ? (
        <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <label htmlFor={`tshirt-${imagePath}`} style={{ fontSize: 10, fontWeight: 'bold', minWidth: '60px' }}>
              T-Shirt:
            </label>
            <input
              type="number"
              id={`tshirt-${imagePath}`}
              min="0"
              value={shirtVersions.tshirt}
              onChange={(e) => handleVersionChange('tshirt', e.target.value)}
              style={{
                width: '50px',
                padding: '2px 4px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '10px'
              }}
            />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <label htmlFor={`longsleeve-${imagePath}`} style={{ fontSize: 10, fontWeight: 'bold', minWidth: '60px' }}>
              Long Sleeve:
            </label>
            <input
              type="number"
              id={`longsleeve-${imagePath}`}
              min="0"
              value={shirtVersions.longsleeve}
              onChange={(e) => handleVersionChange('longsleeve', e.target.value)}
              style={{
                width: '50px',
                padding: '2px 4px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '10px'
              }}
            />
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
            <label htmlFor={`hoodie-${imagePath}`} style={{ fontSize: 10, fontWeight: 'bold', minWidth: '60px' }}>
              Hoodie:
            </label>
            <input
              type="number"
              id={`hoodie-${imagePath}`}
              min="0"
              value={shirtVersions.hoodie}
              onChange={(e) => handleVersionChange('hoodie', e.target.value)}
              style={{
                width: '50px',
                padding: '2px 4px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '10px'
              }}
            />
          </div>
        </div>
      ) : (
        <div style={{ fontSize: 12 }}>
          <div>T-Shirt: {shirtVersions.tshirt || '0'}</div>
          <div>Long Sleeve: {shirtVersions.longsleeve || '0'}</div>
          <div>Hoodie: {shirtVersions.hoodie || '0'}</div>
          <div style={{ fontWeight: 'bold', marginTop: '4px' }}>Total: {totalQuantity}</div>
        </div>
      )}
    </div>
  );
};

export default ShirtVersionCard;
